25	void AddressingResolver::interpret_index(RTLIL::SigSpec signal, int width_down, int width_up)
26	{
27		if (range.isDescending()) {
28			base_offset = -range.right - width_down + 1;
29			raw_signal = signal;
30		} else {
31			base_offset = range.right - width_up + 1;
32	
33			// We might want some other handling of big-endian
34			// indexing.
35			raw_signal = netlist.Not(signal);
36			base_offset += 1;
37		}
38	}
39	
40	AddressingResolver::AddressingResolver(EvalContext &eval, const ast::ElementSelectExpression &sel)
41		: expr(sel), eval(eval), netlist(eval.netlist)
42	{
43		require(sel, sel.value().type->hasFixedRange());
44		range = sel.value().type->getFixedRange();
45		interpret_index(eval.eval_signed(sel.selector()));
46	
47		stride = sel.type->getBitstreamWidth();
48	}
49	
50	AddressingResolver::AddressingResolver(EvalContext &eval, const ast::RangeSelectExpression &sel)
51		: expr(sel), eval(eval), netlist(eval.netlist)
52	{
53		require(sel, sel.value().type->hasFixedRange());
54		range = sel.value().type->getFixedRange();
55	
56		switch (sel.getSelectionKind()) {
57		case ast::RangeSelectionKind::Simple: {
58			auto lv = sel.left().eval(eval.const_), rv = sel.right().eval(eval.const_);
59			ast_invariant(sel, lv.isInteger() && rv.isInteger());
60			raw_signal = {RTLIL::S0};
61	
62			if (range.isDescending())
63				base_offset = rv.integer().as<int>().value() - range.right;
64			else
65				base_offset = range.right - rv.integer().as<int>().value();
66		} break;
67		case ast::RangeSelectionKind::IndexedUp: {
68			RTLIL::SigSpec signal = eval.eval_signed(sel.left());
69			auto rv = sel.right().eval(eval.const_);
70			ast_invariant(sel, rv.isInteger());
71			interpret_index(signal, 1, rv.integer().as<int>().value());
72		} break;
73		case ast::RangeSelectionKind::IndexedDown: {
74			RTLIL::SigSpec signal = eval.eval_signed(sel.left());
75			auto rv = sel.right().eval(eval.const_);
76			ast_invariant(sel, rv.isInteger());
77			interpret_index(signal, rv.integer().as<int>().value(), 1);
78		} break;
79		}
80	
81		if (sel.value().type->isArray())
82			stride = sel.value().type->getArrayElementType()->getBitstreamWidth();
83		else
84			stride = 1;
85	}
86	
87	RTLIL::SigSpec AddressingResolver::shift_up_bitwise(
88			RTLIL::SigSpec val, bool oor_undef, int output_len)
89	{
90		int shifted_len = output_len;
91		RTLIL::SigSpec val2 = val, shifted;
92	
93		if (base_offset > 0) {
94			RTLIL::SigSpec padding(oor_undef ? RTLIL::Sx : RTLIL::S0, base_offset);
95			val2 = {val, padding};
96		} else if (base_offset < 0) {
97			shifted_len += -base_offset;
98		}
99	
100		if (oor_undef)
101			shifted = netlist.Shiftx(val2, netlist.Neg(raw_signal, true), true, shifted_len);
102		else
103			shifted = netlist.Shift(val2, false, netlist.Neg(raw_signal, true), true, shifted_len);
104	
105		if (base_offset < 0)
106			return shifted.extract_end(-base_offset);
107		else
108			return shifted;
109	}
110	
111	RTLIL::SigSpec AddressingResolver::shift_up(RTLIL::SigSpec val, bool oor_undef, int output_len)
112	{
113		if (raw_signal.is_fully_def()) {
114			return embed(val, output_len, stride, oor_undef ? RTLIL::Sx : RTLIL::S0);
115		} else if (stride == 1) {
116			return shift_up_bitwise(val, oor_undef, output_len);
117		} else {
118			RTLIL::SigSpec ret(RTLIL::Sm, output_len);
119	
120			for (int i = 0; i < stride; i++) {
121				RTLIL::SigSpec fin, fout;
122	
123				for (int j = i; j < val.size(); j += stride)
124					fin.append(val[j]);
125	
126				fout = shift_up_bitwise(fin, oor_undef, (output_len - i + stride - 1) / stride);
127				for (int j = 0; j < fout.size(); j++)
128					ret[j * stride + i] = fout[j];
129			}
130	
131			for (auto bit : ret)
132				log_assert(bit != RTLIL::Sm);
133	
134			return ret;
135		}
136	}
137	
138	template <> VariableBits AddressingResolver::extract<VariableBits>(VariableBits val, uint64_t width)
139	{
140		ast_invariant(expr, raw_signal.is_fully_def());
141		int64_t iwidth = (int64_t)width;
142		int64_t offset = raw_signal.as_const().as_int(true) + base_offset;
143		int64_t valsize = (int64_t)val.bitwidth();
144	
145		VariableBits ret;
146		ret.append(Variable::dummy(std::clamp<int64_t>(-offset * stride, 0, iwidth)));
147		int64_t start = std::clamp<int64_t>(offset * stride, 0, valsize);
148		int64_t end = std::clamp<int64_t>(offset * stride + iwidth, 0, valsize);
149		ret.append(val.extract(start, end - start));
150		ret.append(Variable::dummy(std::clamp<int64_t>(iwidth - (-offset * stride + valsize), 0, iwidth)));
151		log_assert(ret.bitwidth() == width);
152	
153		return ret;
154	}
155	
156	template <>
157	RTLIL::SigSpec AddressingResolver::extract<RTLIL::SigSpec>(RTLIL::SigSpec val, uint64_t width)
158	{
159		ast_invariant(expr, raw_signal.is_fully_def());
160		int64_t iwidth = (int64_t)width;
161		int64_t offset = raw_signal.as_const().as_int(true) + base_offset;
162		int64_t valsize = (int64_t)val.size();
163	
164		RTLIL::SigSpec ret;
165		ret.append(RTLIL::SigSpec(RTLIL::Sx, (int)std::clamp<int64_t>(-offset * stride, 0, iwidth)));
166		int64_t start = std::clamp<int64_t>(offset * stride, 0, valsize);
167		int64_t end = std::clamp<int64_t>(offset * stride + iwidth, 0, valsize);
168		ret.append(val.extract((int)start, (int)(end - start)));
169		ret.append(RTLIL::SigSpec(
170				RTLIL::Sx, (int)std::clamp<int64_t>(iwidth - (-offset * stride + valsize), 0, iwidth)));
171		log_assert((int64_t)ret.size() == iwidth);
172	
173		return ret;
174	}
