176	RTLIL::SigSpec AddressingResolver::raw_demux(RTLIL::SigSpec val, int from, int to)
177	{
178		log_assert(val.size() == stride);
179		RTLIL::SigSpec negative, positive;
180	
181		if (from < 0) {
182			// Build the negative branch
183			int demux_size = std::bit_ceil((unsigned int)-from);
184			int sel_size = ceil_log2(demux_size);
185	
186			RTLIL::SigSpec sel = raw_signal;
187			sel.extend_u0(sel_size, true);
188	
189			// check `raw_signal` is in between -2**sel_size...0
190			// which is where the demuxing is valid
191			RTLIL::SigSpec valid = netlist.LogicAnd(
192					netlist.Ge(raw_signal, {RTLIL::S1, RTLIL::SigSpec(RTLIL::S0, sel_size)}, true),
193					netlist.Lt(raw_signal, {RTLIL::S0}, true));
194	
195			RTLIL::SigSpec val_gated = netlist.Mux(RTLIL::SigSpec(RTLIL::S0, stride), val, valid);
196	
197			negative = netlist.Demux(val_gated, sel).extract_end((stride << sel_size) + from * stride);
198			log_assert(negative.size() == -from * stride);
199		}
200	
201		if (to > 0) {
202			// Build the nonnegative branch
203			int demux_size = std::bit_ceil((unsigned int)to);
204			int sel_size = ceil_log2(demux_size);
205	
206			RTLIL::SigSpec sel = raw_signal;
207			sel.extend_u0(sel_size, true);
208	
209			// check `raw_signal` is in between 0...2**sel_size
210			// which is where the demuxing is valid
211			RTLIL::SigSpec valid = netlist.LogicAnd(netlist.Ge(raw_signal, {RTLIL::S0}, true),
212					netlist.Lt(raw_signal, {RTLIL::S0, RTLIL::S1, RTLIL::SigSpec(RTLIL::S0, sel_size)},
213							true));
214	
215			RTLIL::SigSpec val_gated = netlist.Mux(RTLIL::SigSpec(RTLIL::S0, stride), val, valid);
216	
217			positive = netlist.Demux(val_gated, sel).extract(0, to * stride);
218			log_assert(positive.size() == to * stride);
219		}
220	
221		return {positive, negative};
222	}
223	
224	RTLIL::SigSpec AddressingResolver::demux(RTLIL::SigSpec val, int output_len)
225	{
226		log_assert(val.size() == stride);
227		log_assert(output_len % stride == 0);
228		RTLIL::SigSpec demuxed = raw_demux(
229				val, -std::max(0, base_offset), std::max(0, output_len / stride - base_offset));
230	
231		return demuxed.extract(std::max(0, -stride * base_offset), output_len);
232	}
233	
234	RTLIL::SigSpec AddressingResolver::raw_mux(RTLIL::SigSpec val, int from, int to, int stride)
235	{
236		log_assert(stride * (to - from) == val.size());
237		RTLIL::SigSpec negative(RTLIL::Sx, stride), positive(RTLIL::Sx, stride);
238	
239		if (from < 0) {
240			// Build the negative branch
241			int mux_size = std::bit_ceil((unsigned int)-from);
242			int sel_size = ceil_log2(mux_size);
243	
244			RTLIL::SigSpec val_cut = val.extract(0, -from * stride);
245			RTLIL::SigSpec val_padded = {
246					val_cut, RTLIL::SigSpec(RTLIL::Sx, (1 << sel_size) * stride - val_cut.size())};
247	
248			RTLIL::SigSpec sel = raw_signal;
249			sel.extend_u0(sel_size, true);
250			RTLIL::SigSpec valid =
251					netlist.Ge(raw_signal, {RTLIL::S1, RTLIL::SigSpec(RTLIL::S0, sel_size)}, true);
252			negative = netlist.Mux(
253					RTLIL::SigSpec(RTLIL::Sx, stride), netlist.Bmux(val_padded, sel), valid);
254		}
255	
256		if (to > 0) {
257			// Build the positive branch
258			int mux_size = std::bit_ceil((unsigned int)to);
259			int sel_size = ceil_log2(mux_size);
260	
261			RTLIL::SigSpec val_cut = val.extract_end(-from * stride);
262			RTLIL::SigSpec val_padded = {
263					RTLIL::SigSpec(RTLIL::Sx, (1 << sel_size) * stride - val_cut.size()), val_cut};
264	
265			RTLIL::SigSpec sel = raw_signal;
266			sel.extend_u0(sel_size, true);
267			RTLIL::SigSpec valid = netlist.Lt(
268					raw_signal, {RTLIL::S0, RTLIL::S1, RTLIL::SigSpec(RTLIL::S0, sel_size)}, true);
269	
270			positive = netlist.Mux(
271					RTLIL::SigSpec(RTLIL::Sx, stride), netlist.Bmux(val_padded, sel), valid);
272		}
273	
274		return netlist.Mux(positive, negative, raw_signal.msb());
275	}
276	
277	RTLIL::SigSpec AddressingResolver::mux(RTLIL::SigSpec val, int output_len)
278	{
279		log_assert(output_len == stride);
280		log_assert(val.size() % stride == 0);
281		if (raw_signal.is_fully_def())
282			return extract(val, output_len);
283		return raw_mux({RTLIL::SigSpec(RTLIL::Sx, std::max(0, base_offset * stride - val.size())), val,
284							   RTLIL::SigSpec(RTLIL::Sx, std::max(0, stride * -base_offset))},
285				-std::max(0, base_offset), std::max(0, -base_offset + val.size() / stride), output_len);
286	}
287	
288	RTLIL::SigSpec AddressingResolver::shift_down_bitwise(RTLIL::SigSpec val, int output_len)
289	{
290		int shifted_len = output_len;
291		RTLIL::SigSpec val2 = val, shifted;
292	
293		if (base_offset > 0)
294			shifted_len += base_offset;
295		else if (base_offset < 0)
296			val2 = {val, RTLIL::SigSpec(RTLIL::Sx, -base_offset)};
297	
298		shifted = netlist.Shiftx(val2, raw_signal, true, shifted_len);
299	
300		if (base_offset > 0)
301			return shifted.extract_end(base_offset);
302		else
303			return shifted;
304	}
305	
306	RTLIL::SigSpec AddressingResolver::shift_down(RTLIL::SigSpec val, int output_len)
307	{
308		if (raw_signal.is_fully_def()) {
309			return extract(val, output_len);
310		} else if (stride == 1) {
311			return shift_down_bitwise(val, output_len);
312		} else {
313			RTLIL::SigSpec ret(RTLIL::Sm, output_len);
314	
315			for (int i = 0; i < stride; i++) {
316				RTLIL::SigSpec fin, fout;
317	
318				for (int j = i; j < val.size(); j += stride)
319					fin.append(val[j]);
320	
321				fout = shift_down_bitwise(fin, (output_len - i + stride - 1) / stride);
322				for (int j = 0; j < fout.size(); j++)
323					ret[j * stride + i] = fout[j];
324			}
325	
326			for (auto bit : ret)
327				log_assert(bit != RTLIL::Sm);
328	
329			return ret;
330		}
331	}
332	
333	RTLIL::SigSpec AddressingResolver::embed(
334			RTLIL::SigSpec val, int output_len, int stride, RTLIL::State padding)
335	{
336		ast_invariant(expr, raw_signal.is_fully_def());
337		int offset = raw_signal.as_const().as_int(true) + base_offset;
338	
339		RTLIL::SigSpec ret;
340		ret.append(RTLIL::SigSpec(padding, std::clamp(offset * stride, 0, output_len)));
341		int start = std::clamp(-offset * stride, 0, val.size());
342		int end = std::clamp(-offset * stride + output_len, 0, val.size());
343		ret.append(val.extract(start, end - start));
344		ret.append(RTLIL::SigSpec(
345				padding, std::clamp(output_len - offset * stride - val.size(), 0, output_len)));
346		log_assert(ret.size() == output_len);
347	
348		return ret;
349	}
350	
351	bool AddressingResolver::is_static()
352	{
353		return raw_signal.is_fully_def();
354	}
355	
356	}; // namespace slang_frontend
