	bool static_ = inner.static_;
	bool contiguous_slice_ = inner.contiguous_slice_;
	return LValue(MemberAccess{base_offset, std::make_unique<LValue>(std::move(inner))}, bitsize,
			static_, contiguous_slice_);
}

