module base2(i1, i2, sel);
	parameter MSB = 0;
	parameter LSB = 0;
	localparam big_endian = MSB < LSB;

	input [2:0] sel;
	input [MSB:LSB] i1;
	input [1:0] i2;

	reg [MSB:LSB] data;
	always @* begin
		data = i1;
		data[sel-:2] = i2;
	end

	reg [MSB:LSB] data2;
	wire signed [3:0] sel_signed = sel;
	always @* begin
		data2 = i1;
		if (big_endian) begin
			data2[sel_signed] = i2[0];
			data2[sel_signed - 1] = i2[1];
		end else begin
			data2[sel_signed - 1] = i2[0];
			data2[sel_signed] = i2[1];
		end
	end

	always @* begin
		if (sel[0] === 1'bx ||
				sel[1] === 1'bx ||
				sel[2] === 1'bx) begin
			// No guarantees
		end else begin
			assert(data2 === data);
		end
	end
endmodule

